def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Process all triples to create one complex sentence
    main_subject = None
    main_clauses = []
    additional_clauses = []

    # Find the airport subject (most likely to be the main subject)
    for subject, triples_list in subject_map.items():
        if any(p in ["cityServed", "runwayLength", "runwayName", "runwaySurfaceType", "1stRunwayLengthFeet", "1stRunwaySurfaceType"] for p, _ in triples_list):
            main_subject = subject
            break
    if not main_subject:
        main_subject = list(subject_map.keys())[0] if subject_map else ""

    # Process each triple
    for subject, triples_list in subject_map.items():
        for predicate, obj in triples_list:
            if predicate == "cityServed":
                main_clauses.append(f"{main_subject} serves the city of {obj}")
            elif predicate == "mayor":
                additional_clauses.append(f"its mayor is {obj}")
            elif predicate == "isPartOf":
                additional_clauses.append(f"it is part of {obj}")
            elif predicate == "operatingOrganisation":
                additional_clauses.append(f"it is operated by {obj}")
            elif predicate == "location":
                additional_clauses.append(f"it is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                additional_clauses.append(f"it has an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                additional_clauses.append(f"it has a runway length of {obj} metres")
            elif predicate == "country":
                additional_clauses.append(f"it is located in {obj}")
            elif predicate == "capital":
                additional_clauses.append(f"it has {obj} as its capital")
            elif predicate == "language":
                additional_clauses.append(f"its official language is {obj}")
            elif predicate == "leader":
                additional_clauses.append(f"its leader is {obj}")
            elif predicate == "owner":
                additional_clauses.append(f"it is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                additional_clauses.append(f"its first runway is {obj} feet long")
            elif predicate == "1stRunwaySurfaceType":
                additional_clauses.append(f"its first runway has an {obj} surface")
            elif predicate == "3rdRunwayLengthFeet":
                additional_clauses.append(f"its third runway is {obj} feet long")
            elif predicate == "icaoLocationIdentifier":
                additional_clauses.append(f"its ICAO location identifier is {obj}")
            elif predicate == "locationIdentifier":
                additional_clauses.append(f"its location identifier is {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                additional_clauses.append(f"it has an elevation of {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                additional_clauses.append(f"its IATA location identifier is {obj}")
            elif predicate == "nativeName":
                additional_clauses.append(f"its native name is {obj}")
            elif predicate == "leaderParty":
                additional_clauses.append(f"its leader party is {obj}")
            elif predicate == "runwayName":
                additional_clauses.append(f"it has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                additional_clauses.append(f"it has a runway surface type of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                additional_clauses.append(f"it has an elevation of {obj} metres above sea level")
            else:
                # For other predicates, use "has a" format as fallback
                additional_clauses.append(f"it has a {predicate} of {obj}")

    # Construct the final sentence
    if main_clauses:
        sentence = main_clauses[0]
    else:
        sentence = main_subject

    if additional_clauses:
        sentence += " " + ", ".join(additional_clauses)

    return sentence + "."

